let soundLevel = 0
basic.forever(function () {
    if (input.buttonIsPressed(Button.A)) {
        basic.showIcon(IconNames.Yes)
        basic.pause(500)
        soundLevel = input.soundLevelDb()
    } else if (input.buttonIsPressed(Button.B)) {
        basic.clearScreen()
        basic.showNumber(soundLevel)
    } else {
        led.plotBarGraph(
        input.soundLevel(),
        255
        )
    }
})
